public boolean putAll(Object key, Collection values) { if (values == null || values.size() == 0) { return false; } Collection coll = getCollection(key); if (coll == null) { coll = createCollection(values.size()); boolean result = coll.addAll(values); if (coll.size() > 0) { getMap().put(key, coll); } return result; } else { return coll.addAll(values); } }